var dbString = source;
logger.info("source approles : " + dbString);
var resultArray = [];
if (dbString != null) {
  try {
    var applicationName = source.ApplicationNameRoleName;
    var applicationId = source.ApplicationRoleID;
    let appnamearray = [];
    let rolenamearray = [];
    let appidarray = [];
    let roleidarray = [];
	let combineArray1 = [];
	let combineArray2 = [];

    var appnamesplit = applicationName.split('|');
	for (var i = 0; i < appnamesplit.length; i++) {
    if (appnamesplit[i]) {
        var appnamesplit2 = appnamesplit[i].split(',');
        for (var j = 0; j < appnamesplit2.length; j += 2) {
            // Add current element to appnamearray
            appnamearray = appnamearray.concat(appnamesplit2[j]);         
            // Add next element to rolenamearray, if it exists
            if (j + 1 < appnamesplit2.length) {				
				rolenamearray = rolenamearray.concat(appnamesplit2[j + 1]);			              
            }else{
					rolenamearray = rolenamearray.concat("");
				}			
        }		
    }
	}
    // Process application IDs
    var appidsplit = applicationId.split('|');
	for (var i = 0; i < appidsplit.length; i++) {
    if (appidsplit[i]) {
		var appId;
		var roleId;
        var appidsplit2 = appidsplit[i].split(',');
        for (var j = 0; j < appidsplit2.length; j += 2) {
			//query business app MO to get _id
			var applicationResponse = openidm.query(
				"managed/alpha_kyid_businessapplication",
				{
					"_queryFilter": 'name eq "' + appidsplit2[j] + '"'
				},
				["_id"]
			);
			if (applicationResponse.result && applicationResponse.result.length > 0) {
              logger.error("application response length greater than 0");
				appId = applicationResponse.result[0]._id;
              logger.error("appID : "+appId);
				// Add current element to appidarray
				appidarray = appidarray.concat(appId);
              logger.error("appidarray1 : "+appidarray);
			}else{
              logger.error("application response length less than 0");
				appidarray = appidarray.concat("");
              logger.error("appidarray2 : "+appidarray);
			}

            // Add next element to roleidarray, if it exists
            if (j + 1 < appidsplit2.length) {
				//query role MO to get _id
				var roleResponse = openidm.query(
					"managed/alpha_role",
					{
						"_queryFilter": 'businessRoleId eq "' + appidsplit2[j + 1] + '"'
					},
					["_id"]
				);	 
				if (roleResponse.result && roleResponse.result.length > 0) {					
					roleId = roleResponse.result[0]._id;
				}			
                roleidarray = roleidarray.concat(roleId);             								
            }else{
				roleidarray = roleidarray.concat("");
			}
        }
    }
	}
	if((appnamearray.length == appidarray.length) &&
		(rolenamearray.length == roleidarray.length)){
		logger.error("lengths are matching");
		for(var i = 0; i < appnamearray.length; i++){
			 resultArray.push({
			  "applicationId": appidarray[i].toString(),
			  "applicationName": appnamearray[i].toString(),
			  "roleId": roleidarray[i].toString(),
			  "roleName": rolenamearray[i].toString(),
			  "orginalDelegatorIdentifierAttributeName": "",
			  "orginalDelegatorIdentifierAttributeValue": "",
			  "originalDelegatorUserAccountId": "",
			  "currentDelegatorIdentifierAttributeName": "",
			  "currentDelegatorIdentifierAttributeValue": "",
			  "currentDelegatorUserAccountId": "",
			  "orgType":"",
			  "orgId":"",
			  "orgName":"",
			  "orgSourceUniqueId":"",
			  "businessKeyId":"",
			  "businessKeyName":"",
			  "businessKeyTypeName":"",
			  "businessKeyDescription":"",
			  "kogOrgBusinessKeyId":"",
			  "delegationEndDate":"",
			  "isForwardDelegable":"",
			  "delegationEndDateEpoch":""
			});
			logger.error("resultArray : "+JSON.stringify(resultArray));		
			resultArray;
		}

	}else{
		logger.error("lengths not matching");
	}    
  } catch (error) {
    logger.error("exception : " + error);
  }
}

